// =============================================
// PARSE INCOMING REQUEST
// Handles: text messages, session IDs, and
// optional image uploads from binary OR JSON POST
// fields such as images, postImages, image, etc.
// =============================================

const input = $input.first();
const body = input.json || {};
const binaryData = input.binary || {};

// --- Extract message ---
const message = body.message || body.text || body.query || body.chatInput || '';
const sessionId = body.sessionId || body.session_id || body.userId || body.user_id || 'session-default';
const requestPdf = body.generatePdf === true || body.generate_pdf === true || body.pdf === true;
const requestImageGen = body.generateImage === true || body.generateImage === 'true' || body.generate_image === true || body.generate_image === 'true' || body.requestImageGen === true || body.requestImageGen === 'true';

// --- Normalize uploaded image (selfie / reference / post image) ---
let hasReferenceImage = false;
let referenceImageBase64 = '';
let referenceImageMimeType = 'image/jpeg';
let uploadedImages = [];

function parseDataUrl(value) {
  const match = String(value || '').match(/^data:(image\/[a-zA-Z0-9.+-]+);base64,(.+)$/);
  return match ? { mimeType: match[1], data: match[2].replace(/\s/g, '') } : null;
}

function addImage(value, fallbackMimeType = 'image/jpeg') {
  if (!value) return;

  if (typeof value === 'string') {
    const dataUrl = parseDataUrl(value);
    if (dataUrl) {
      uploadedImages.push(dataUrl);
      return;
    }

    const compact = value.replace(/\s/g, '');
    if (/^[A-Za-z0-9+/_=-]+$/.test(compact) && compact.length > 80) {
      uploadedImages.push({ mimeType: fallbackMimeType, data: compact });
    }
    return;
  }

  if (Array.isArray(value)) {
    value.forEach((item) => addImage(item, fallbackMimeType));
    return;
  }

  if (typeof value === 'object') {
    const mimeType = value.mimeType || value.mime_type || value.type || fallbackMimeType;
    addImage(value.dataUrl || value.data_url || value.base64 || value.data || value.image || value.src || value.url, mimeType);
  }
}

const imageKeys = Object.keys(binaryData).filter((key) =>
  binaryData[key] && binaryData[key].mimeType && binaryData[key].mimeType.startsWith('image/')
);

for (const key of imageKeys) {
  const img = binaryData[key];
  addImage({ data: img.data || '', mimeType: img.mimeType || 'image/jpeg' });
}

addImage(body.images);
addImage(body.postImages);
addImage(body.post_images);
addImage(body.uploadedImages);
addImage(body.uploaded_images);
addImage(body.attachments);
addImage(body.files);
addImage(body.image);
addImage(body.postImage);
addImage(body.post_image);
addImage(body.imageBase64 || body.image_base64, body.imageMimeType || body.image_mime_type || 'image/jpeg');

if (uploadedImages.length > 0) {
  hasReferenceImage = true;
  referenceImageBase64 = uploadedImages[0].data || '';
  referenceImageMimeType = uploadedImages[0].mimeType || 'image/jpeg';
}

return [{
  json: {
    message,
    sessionId,
    requestPdf,
    requestImageGen,
    hasReferenceImage,
    referenceImageBase64,
    referenceImageMimeType,
    uploadedImages,
    uploadedImageCount: uploadedImages.length,
    imageContext: hasReferenceImage
      ? 'User uploaded an image with the post/webhook request. Use it as the reference image when the user asks for same face, post image, photo editing, or personalized visuals.'
      : 'No reference image was uploaded. Generate images without a specific face reference unless the user provides one.',
    timestamp: new Date().toISOString()
  }
}];

// =============================================
// PARSE AGENT RESPONSE
// Detects image/PDF commands embedded in output.
// Supports both legacy { command: "GENERATE_IMAGE" }
// and webhook JSON { generateImage: "true", prompt: "..." }.
// =============================================

const agentOutput = $input.first().json.output || $input.first().json.text || '';
const ctx = $('Parse Input & Detect Image').first().json;

function parseJsonBlocks(text) {
  const blocks = [];
  const fenced = text.matchAll(/```json\s*([\s\S]*?)\s*```/gi);
  for (const match of fenced) {
    try { blocks.push(JSON.parse(match[1])); } catch(e) {}
  }

  const trimmed = text.trim();
  if (trimmed.startsWith('{') && trimmed.endsWith('}')) {
    try { blocks.push(JSON.parse(trimmed)); } catch(e) {}
  }

  return blocks;
}

const jsonBlocks = parseJsonBlocks(agentOutput);
let imageCommand = null;
let pdfCommand = null;

for (const block of jsonBlocks) {
  if (!block || typeof block !== 'object') continue;

  const wantsImage = block.command === 'GENERATE_IMAGE' || block.generateImage === true || block.generateImage === 'true' || block.generate_image === true || block.generate_image === 'true';
  if (wantsImage && !imageCommand) {
    imageCommand = {
      command: 'GENERATE_IMAGE',
      prompt: block.prompt || block.imagePrompt || block.image_prompt || '',
      style: block.style || 'professional viral marketing thumbnail, bold typography overlay space, high contrast colors, social media optimized, cinematic lighting, modern composition, clean digital platform style',
      size: block.size || '1024x1024',
      useReferenceImage: block.useReferenceImage === true || block.useReferenceImage === 'true' || ctx.hasReferenceImage === true
    };
  }

  if ((block.command === 'GENERATE_PDF' || block.generatePdf === true || block.generate_pdf === true) && !pdfCommand) {
    pdfCommand = block;
  }
}

const cleanOutput = agentOutput
  .replace(/```json[\s\S]*?```/g, '')
  .replace(/^\s*{[\s\S]*}\s*$/g, '')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

let routeTo = 'text_only';
if (imageCommand && imageCommand.prompt) {
  routeTo = (imageCommand.useReferenceImage && ctx.hasReferenceImage)
    ? 'image_with_face'
    : 'image_no_face';
} else if (pdfCommand) {
  routeTo = 'pdf_only';
}

return [{
  json: {
    agentOutput,
    cleanOutput,
    imageCommand,
    pdfCommand,
    routeTo,
    sessionId: ctx.sessionId,
    hasReferenceImage: ctx.hasReferenceImage,
    referenceImageBase64: ctx.referenceImageBase64 || '',
    referenceImageMimeType: ctx.referenceImageMimeType || 'image/jpeg',
    uploadedImages: ctx.uploadedImages || [],
    uploadedImageCount: ctx.uploadedImageCount || 0,
    requestPdf: ctx.requestPdf || false,
    timestamp: ctx.timestamp
  }
}];

// =============================================
// PREPARE FACE REFERENCE
// Enhances the image prompt to incorporate
// the user's uploaded selfie as face reference
// Uses DALL-E 3 with descriptive face guidance
// (For EXACT face swap: swap this node for a
//  Replicate/InstantID HTTP Request instead)
// =============================================

const data = $input.first().json;
const cmd = data.imageCommand || {};

// Build enhanced prompt describing face reference intent
const enhancedPrompt = `${cmd.prompt}. The featured person should match the reference individual's facial features, hairstyle, and likeness closely. ${cmd.style}. Professional marketing thumbnail. Viral social media aesthetic. Bold composition.`;

return [{
  json: {
    ...data,
    enhancedPrompt,
    dalleSize: cmd.size || '1024x1024',
    faceRefNote: 'Warning: DALL-E 3 approximates face reference via prompt. For pixel-accurate face replication, connect a Replicate/InstantID node and swap this code node for it.'
  }
}];

// =============================================
// PROCESS IMAGE RESULT
// Normalizes output from both DALL-E paths
// and prepares for PDF (if requested) or
// direct response
// =============================================

const dalleResult = $input.first().json;
const ctx = $('Parse Agent Response').first().json;

// Extract generated image URL
const imageUrl = (dalleResult.data && dalleResult.data[0])
  ? dalleResult.data[0].url
  : null;

const revisedPrompt = (dalleResult.data && dalleResult.data[0])
  ? dalleResult.data[0].revised_prompt
  : ctx.imageCommand?.prompt || '';

return [{
  json: {
    ...ctx,
    generatedImageUrl: imageUrl,
    revisedPrompt,
    imageGenerated: !!imageUrl,
    // If user originally requested PDF, flow through to PDF builder
    nextStep: ctx.requestPdf ? 'build_pdf' : 'respond_image'
  }
}];

// =============================================
