return [{
  json: {
    success: true,
    type: 'pdf_response',
    sessionId: ctx.sessionId,
    message: ctx.cleanOutput,
    timestamp: new Date().toISOString(),
    result: {
      hasPdf: true,
      pdfUrl: pdfUrl,
      hasImage: !!ctx.generatedImageUrl,
      imageUrl: ctx.generatedImageUrl || null,
      imageUsedFaceReference: ctx.hasReferenceImage && ctx.imageCommand?.useReferenceImage,
      pdfTitle: ctx.pdfCommand?.title || 'Marketing Report'
    },
    meta: {
      commandDetected: ctx.imageCommand ? 'IMAGE+PDF' : 'PDF',
      sessionId: ctx.sessionId,
      agentVersion: 'Viral Marketing AI Agent v1.0'
    }
  }
}];

